const __pageData = JSON.parse('{"title":"抽象解释：静态分析的理论基础","description":"从 Galois 连接的形式化框架到 TypeScript 类型检查器与 ESLint 的静态分析实践，系统阐述抽象解释理论及其在现代工程中的映射。","frontmatter":{"title":"抽象解释：静态分析的理论基础","description":"从 Galois 连接的形式化框架到 TypeScript 类型检查器与 ESLint 的静态分析实践，系统阐述抽象解释理论及其在现代工程中的映射。","date":"2026-05-01T00:00:00.000Z","tags":["编程原理","抽象解释","静态分析","形式化方法","Galois 连接","类型系统","程序分析"],"category":"theoretical-foundations"},"headers":[],"relativePath":"programming-principles/07-abstract-interpretation.md","filePath":"programming-principles/07-abstract-interpretation.md","lastUpdated":1777710141000}');
